#include <stdio.h>

// Defining an enum with explicit and implicit values
enum ProtocolState {
    STATE_DISCONNECTED, // Defaults to 0
    STATE_CONNECTING,   // Defaults to 1
    STATE_CONNECTED,    // Defaults to 2
    STATE_ERROR = -1,   // Explicitly set to -1
    STATE_TIMEOUT       // Defaults to previous + 1, which is 0!
};

// Using typedef to define a cleaner enum type
typedef enum {
    ROLE_GUEST = 100,
    ROLE_USER = 200,
    ROLE_ADMIN = 300
} UserRole;

int main() {
    enum ProtocolState current_state = STATE_CONNECTING;
    UserRole active_role = ROLE_ADMIN;

    printf("Current State Value: %d\n", current_state);
    printf("Timeout State Value: %d\n", STATE_TIMEOUT);
    printf("User Role Code: %d\n", active_role);

    return 0;
}

codeExample2.code:
#include <stdio.h>

typedef enum {
    STATUS_OK,
    STATUS_WARNING,
    STATUS_CRITICAL,
    STATUS_UNKNOWN
} SystemStatus;

void handle_status(SystemStatus status) {
    switch (status) {
        case STATUS_OK:
            printf("System Operational.\n");
            break;
        case STATUS_WARNING:
            printf("Warning detected. Monitor resources.\n");
            break;
        case STATUS_CRITICAL:
            printf("Critical Alert! Initiating shutdown procedure.\n");
            break;
        case STATUS_UNKNOWN:
        default:
            printf("Status ambiguous. Run self-diagnostics.\n");
            break;
    }
}

int main() {
    SystemStatus current_sys = STATUS_CRITICAL;
    printf("Sending alert for status code: %d\n", current_sys);
    handle_status(current_sys);
    return 0;
}

