#include <stdio.h>

typedef enum { OVEN_OFF, OVEN_PREHEATING, OVEN_READY, OVEN_BAKING } OvenState;

OvenState update_oven(OvenState current) {
    switch(current) {
        case OVEN_OFF:
            printf("Turning on oven... Preheating started.\n");
            return OVEN_PREHEATING;
        case OVEN_PREHEATING:
            printf("Target temperature reached! Oven Ready.\n");
            return OVEN_READY;
        case OVEN_READY:
            printf("Food inserted! Baking started.\n");
            return OVEN_BAKING;
        case OVEN_BAKING:
            printf("Baking complete! Shutting down.\n");
            return OVEN_OFF;
        default:
            return OVEN_OFF;
    }
}

int main() {
    OvenState state = OVEN_OFF;
    state = update_oven(state);
    state = update_oven(state);
    return 0;
}
```

A lookup array maps enum values directly to string pointers using index offsets. Example:

```c
typedef enum { ERR_SUCCESS, ERR_NOT_FOUND, ERR_TIMEOUT, ERR_MAX_VAL } ErrorCode;

const char* ErrorStrings[] = {
    [ERR_SUCCESS] = "Success",
    [ERR_NOT_FOUND] = "Not Found",
    [ERR_TIMEOUT] = "Timeout"
};
```
This operates at constant O(1) time complexity directly via pointer offsets, bypassing conditional switch branches. However, its main limitation is that it requires sequential enum values starting at 0. If there are huge gaps in enum numbers (e.g., 100 to 400), the array will be extremely sparse and waste considerable memory.

